import { Component } from '@angular/core';
import { CommonModule, CurrencyPipe } from '@angular/common';
import { CdbService } from '../../services/cdb.service';
import { CdbCalculationResult } from '../../models/cdb.model';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';

@Component({
  selector: 'app-cdb-calculator',
  providers: [CurrencyPipe],
  templateUrl: './cdb-calculator.component.html',
  styleUrls: ['./cdb-calculator.component.scss']
})
export class CdbCalculatorComponent {
  calculationForm: FormGroup;
  result: CdbCalculationResult | null = null;
  isLoading = false;
  errorMessage: string | null = null;

  constructor(
    private readonly fb: FormBuilder,
    private readonly cdbService: CdbService,
    private readonly currencyPipe: CurrencyPipe
  ) {
    this.calculationForm = this.fb.group({
      initialValue: [null, [Validators.required]],
      months: [null, [Validators.required, Validators.min(2), Validators.pattern('^[0-9]+$')]]
    });
  }

  get initialValueControl() {
    return this.calculationForm.get('initialValue');
  }

  get monthsControl() {
    return this.calculationForm.get('months');
  }

  onInputInitialValue(): void {
    const control = this.initialValueControl;
    let rawValue = control?.value || "";

    const cleanValue = rawValue.toString().replace(/\D/g, '');

    // Atualiza o campo apenas com números enquanto digita
    if (!cleanValue) {
      control?.setValue('', { emitEvent: false });
      return;
    }

    const numericValue = Number(cleanValue);

    const formatted = this.currencyPipe.transform(
      numericValue,
      'BRL',
      'symbol',
      '1.2-2',
      'pt-BR'
    );

    control?.setValue(formatted, { emitEvent: false });

    if (numericValue === 0) {
      control?.setErrors({ 'isZero': true });
    } else {      
      if (control?.hasError('isZero')) {
        control.setErrors(null);
      }
    }
  }

  formatInitialValue(): void {
    const control = this.initialValueControl;
    const rawValue = control?.value || "";

    // Remove tudo que não é número
    const plainValue = rawValue.toString().replace(/\D/g, '');

    if (!plainValue) return;

    const numericValue = Number(plainValue); // Trata como centavos

    if (numericValue === 0) {
      control?.setErrors({ 'isZero': true });
      return;
    }

    const formatted = this.currencyPipe.transform(numericValue, 'BRL', 'symbol', '1.2-2', 'pt-BR');
    control?.setValue(formatted, { emitEvent: false });
  }

  onSubmit(): void {
    if (this.calculationForm.invalid) {
      this.calculationForm.markAllAsTouched();
      return;
    }

    this.isLoading = true;

    const rawValue = this.initialValueControl?.value || "";
    const valorInvestido = Number(rawValue.replace(/\D/g, '')) / 100; 

    const meses = this.calculationForm.value.months;

    this.cdbService.calculate({ valorInvestido, meses }).subscribe({
      next: (data) => {
        this.result = data;
        this.isLoading = false;
      },
      error: () => {
        this.errorMessage = 'Ocorreu um erro ao calcular. Verifique os dados e tente novamente.';
        this.isLoading = false;
      }
    });
  }

  onReset(): void {
    this.calculationForm.reset();
    this.result = null;
    this.errorMessage = null;
  }
}
